  const db = acquireWorkerDb();
  const row = db.prepare(`
    SELECT id, state, spec_folder, paths_json, files_total, files_processed, errors_json, created_at, updated_at, governance_json
    FROM ingest_jobs
    WHERE id = ?
  `).get(jobId) as IngestJobRow | undefined;
